import * as fs from 'fs';
import * as path from 'path';

const formalPath = path.join(process.cwd(), 'open-source/aeon/FORMAL_LEDGER.md');
const theoremPath = path.join(process.cwd(), 'open-source/gnosis/THEOREM_LEDGER.md');
const ownershipPath = path.join(process.cwd(), 'open-source/gnosis/scripts/ledger-mcp-ownership.ts');
const coveragePath = path.join(process.cwd(), 'open-source/gnosis/scripts/generate-ledger-mcp-coverage.ts');

const formalText = fs.readFileSync(formalPath, 'utf8');
const theoremText = fs.readFileSync(theoremPath, 'utf8');
const ownershipText = fs.readFileSync(ownershipPath, 'utf8');
let coverageText = fs.readFileSync(coveragePath, 'utf8');

const newOwnerships: string[] = [];

const map = new Map<string, string[]>();
let curSec: string | null = null;

for (const line of formalText.split('\n')) {
  if (line.startsWith('## ') || line.startsWith('### ')) {
    curSec = line.trim();
    map.set(curSec, []);
  } else if (curSec && line.startsWith('- **')) {
    map.get(curSec)?.push(line.trim());
  }
}

let theoremOut = theoremText;
let addedCount = 0;

for (const [sec, lines] of map.entries()) {
  const normSec = sec.replace(/^[#]+ \s*/, '').replace(/\(.*\)/g, '').trim();
  if (!theoremText.includes(sec)) {
    addedCount++;
    console.log('Adding section:', normSec);
    const rows = lines.map(line => {
      const match = line.match(/^- \*\*(.+?)(?: \((THM-[^)]+)\))?\*\*:?\s*(.*)$/i);
      if (!match) return null;
      let [, title, thmId, desc] = match;
      if (!thmId) {
        thmId = 'THM-' + title.toUpperCase().replace(/[^A-Z0-9]+/g, '-').replace(/-$/, '');
      }
      return `| \`${thmId}\` | ${desc} | ${title} | Pending ${normSec} | Conceptual |`;
    }).filter(Boolean);
    
    if (rows.length > 0) {
      const toAppend = `\n\n${sec}\n\n*Auto-imported from FORMAL_LEDGER.md*\n\n| ID | Claim (paper-level) | Explicit assumptions | Mechanization | Status |\n|---|---|---|---|---|\n` + rows.join('\n');
      theoremOut += toAppend;
    } else {
      const toAppend = `\n\n${sec}\n\n*Domain boundary imported from FORMAL_LEDGER.md*`;
      theoremOut += toAppend;
    }
    
    if (!ownershipText.includes(normSec)) {
       newOwnerships.push(`  '${normSec}': { server: 'topology-mcp' },`);
    }
  }
}

fs.writeFileSync(theoremPath, theoremOut);

if (newOwnerships.length > 0) {
  const parts = ownershipText.split('export const OVERRIDE_SERVER_MAPPINGS: Record<string, ServerMapping> = {');
  if(parts.length === 2) {
    fs.writeFileSync(ownershipPath, parts[0] + 'export const OVERRIDE_SERVER_MAPPINGS: Record<string, ServerMapping> = {\n' + newOwnerships.join('\n') + parts[1]);
  }
}

const oldMatch = coverageText.match(/export const EXPECTED_CANONICAL_LEDGER_SECTION_COUNT = (\d+);/);
if (oldMatch) {
  const newCount = parseInt(oldMatch[1]) + addedCount;
  coverageText = coverageText.replace(oldMatch[0], `export const EXPECTED_CANONICAL_LEDGER_SECTION_COUNT = ${newCount};`);
  fs.writeFileSync(coveragePath, coverageText);
  console.log('Updated section count from', oldMatch[1], 'to', newCount);
}

console.log('Done mapping', addedCount, 'sections.');
